# setup_default_parameters ----
## Setup ----
data <- FIMS::FIMSFrame(data_big)

## IO correctness ----
test_that("`setup_default_parameters()` works with correct inputs", {
  result <- setup_default_parameters(data = data)

  #' @description Test that output is a `tbl_df`.
  expect_s3_class(result, "tbl_df")

  #' @description Test that output has the expected column structure.
  expect_equal(
    colnames(result),
    c(
      "module_name", "fleet", "module_type", "label",
      "age", "length", "time", "value", "estimation_type",
      "distribution_type", "distribution"
    )
  )

  #' @description Test that key modules are included in the output.
  expect_true(all(c(
    "Fleet", "Selectivity", "Recruitment", "Maturity", "Growth", "Population"
  ) %in% unique(result[["module_name"]])))

  #' @description Test that output includes at least one configured parameter row.
  expect_gt(nrow(result), 0)

  clear()

  #' @description Test that the generated parameter values have not changed from the accepted snapshot.
  expect_snapshot_file(
    save_csv(result),
    "default_parameters.csv",
    compare = compare_file_text
  )
})

test_that("modular pipeline matches `setup_default_parameters()`", {
  fleet1_name <- "fleet1"

  fleet1_selectivity_defaults <- setup_default_selectivity(
    data = data,
    fleet = fleet1_name
  )

  fleet1_fleet_defaults <- setup_default_fleet(
    data = data,
    fleet = fleet1_name
  )

  survey1_name <- "survey1"

  survey1_selectivity_defaults <- setup_default_selectivity(
    data = data,
    fleet = survey1_name
  )

  survey1_fleet_defaults <- setup_default_fleet(
    data = data,
    fleet = survey1_name
  )

  recruitment_defaults <- setup_default_recruitment(data = data)
  maturity_defaults <- setup_default_maturity(data = data)
  growth_defaults <- setup_default_growth()

  log_m <- log(0.2)
  population_defaults <- setup_default_Population(
    data = data,
    log_M = log_m,
    log_init_naa = setup_default_log_init_naa(
      data = data,
      recruitment_defaults = recruitment_defaults,
      log_m = log_m
    )
  )

  modular_result <- dplyr::bind_rows(
    fleet1_selectivity_defaults,
    fleet1_fleet_defaults,
    survey1_selectivity_defaults,
    survey1_fleet_defaults,
    recruitment_defaults,
    maturity_defaults,
    growth_defaults,
    population_defaults
  )

  expected_result <- setup_default_parameters(data = data)

  #' @description Test that the modular pipeline output is identical to `setup_default_parameters()`.
  expect_equal(
    modular_result |>
      dplyr::arrange(dplyr::across(dplyr::everything())),
    expected_result |>
      dplyr::arrange(dplyr::across(dplyr::everything()))
  )

  clear()
})

test_that("modular pipeline with `purrr` matches `setup_default_parameters()`", {
  model_data <- get_data(data)
  fleets <- model_data |>
    dplyr::pull(.data[["fleet"]]) |>
    na.omit() |>
    unique()

  fleet_defaults <- purrr::map(
    fleets,
    function(fleet_i) {
      setup_default_fleet(data = data, fleet = fleet_i)
    }
  ) |>
    dplyr::bind_rows()

  selectivity_defaults <- purrr::map(
    fleets,
    function(fleet_i) {
      setup_default_selectivity(data = data, fleet = fleet_i)
    }
  ) |>
    dplyr::bind_rows()

  recruitment_defaults <- setup_default_recruitment(data = data)
  maturity_defaults <- setup_default_maturity(data = data)
  growth_defaults <- setup_default_growth()

  log_m <- log(0.2)
  log_init_naa <- setup_default_log_init_naa(
    data = data,
    recruitment_defaults = recruitment_defaults,
    log_m = log_m
  )

  population_defaults <- setup_default_Population(
    data = data,
    log_M = log_m,
    log_init_naa = log_init_naa
  )

  # Explicitly update log_init_naa values to mirror downstream modular workflows.
  population_defaults <- population_defaults |>
    dplyr::rows_update(
      tibble::tibble(
        label = "log_init_naa",
        age = get_ages(data),
        value = log_init_naa
      ),
      by = c("label", "age")
    )

  modular_result <- dplyr::bind_rows(
    selectivity_defaults,
    fleet_defaults,
    recruitment_defaults,
    maturity_defaults,
    growth_defaults,
    population_defaults
  )

  expected_result <- setup_default_parameters(data = data)

  #' @description Test that the modular pipeline output is identical to `setup_default_parameters()`.
  expect_true(identical(modular_result, expected_result))
  expect_equal(modular_result, expected_result)

  clear()
})

## Edge handling ----
test_that("`setup_default_parameters()` works with edge cases", {
  recruitment_without_distribution <- setup_default_recruitment(
    data = data,
    distribution = NA_character_
  )

  #' @description Test that `log_sd` is not created when distribution is not specified.
  log_sd_value <- recruitment_without_distribution |>
    dplyr::filter(.data[["label"]] == "log_sd") |>
    dplyr::pull(.data[["value"]])

  expect_equal(log_sd_value, numeric(0))

  #' @description Test that `log_devs` estimation_type is constant when distribution is not specified.
  log_devs_value <- recruitment_without_distribution |>
    dplyr::filter(.data[["label"]] == "log_devs") |>
    dplyr::pull(.data[["estimation_type"]]) |>
    unique()

  expect_equal(log_devs_value, "constant")

  #' @description Test that `log_devs` distribution_type is `NA` when distribution is not specified.
  log_devs_distribution_type <- recruitment_without_distribution |>
    dplyr::filter(.data[["label"]] == "log_devs") |>
    dplyr::pull(.data[["distribution_type"]]) |>
    unique()

  expect_equal(log_devs_distribution_type, NA_character_)

  clear()
})

## Error handling ----
test_that("`setup_default_parameters()` returns correct error messages", {
  #' @description Test that invalid `data` class triggers an informative error.
  expect_error(
    object = setup_default_parameters(data = "not_a_fimsframe"),
    regexp = "FIMSFrame"
  )

  clear()
})
